from fastapi import APIRouter
from fastapi.responses import HTMLResponse
from fastapi import Request
from jinja2 import Environment, FileSystemLoader
from main import app
import logging

router = APIRouter()

# Create a Jinja2 environment
env = Environment(loader=FileSystemLoader('templates'))

@router.get('/', response_class=HTMLResponse)
def read_root(request: Request):
    try:
        template = env.get_template('index.html')
        return HTMLResponse(content=template.render(), status_code=200)
    except Exception as e:
        logging.error(f'Error rendering template: {e}')
        return HTMLResponse(content='Error rendering template. Please try again later.', status_code=500)

@router.get('/about', response_class=HTMLResponse)
def read_about(request: Request):
    try:
        template = env.get_template('about.html')
        return HTMLResponse(content=template.render(), status_code=200)
    except Exception as e:
        logging.error(f'Error rendering template: {e}')
        return HTMLResponse(content='Error rendering template. Please try again later.', status_code=500)

from fastapi import Request
from fastapi.responses import JSONResponse
from main import app
import logging

# Exception handler
def handle_exception(request: Request, exc: Exception):
    logging.error(f'Error: {exc}')
    # Catch specific exceptions
    if isinstance(exc, ValueError):
        return JSONResponse(status_code=400, content={'error': 'Invalid request'})
    elif isinstance(exc, RuntimeError):
        return JSONResponse(status_code=500, content={'error': 'Internal Server Error'})
    else:
        return JSONResponse(status_code=500, content={'error': 'Unknown error'})
